import { log } from '@/shared/log';
import { mcpErrorJson } from './error';

import type { CallToolResult } from '@modelcontextprotocol/sdk/types.js';

/**
 * Wraps an MCP tool handler so uncaught exceptions never propagate.
 * Returns error info as normal content (isError omitted) for any unhandled throw.
 *
 * This prevents sibling parallel tool calls from failing when one
 * tool encounters an unexpected error.
 */
export function safeHandler<T>(
  handler: (input: T) => Promise<CallToolResult>
): (input: T) => Promise<CallToolResult> {
  return async (input: T) => {
    // eslint-disable-next-line no-restricted-syntax -- intentional last-resort catch to prevent sibling tool call failures
    try {
      return await handler(input);
    } catch (e) {
      log.error('Unhandled tool error', e);
      return mcpErrorJson({
        error: e instanceof Error ? e.message : String(e),
        cause: 'unhandled_exception',
      });
    }
  };
}
