import { mcpError, mcpSuccessJson, safeHandler } from './response';

import { DESCRIPTIONS } from '@/shared/descriptions';
import type { RegisterTools } from '@/server/types';
import { bridge, bridgeSchema } from '@/operations/bridge';

const toolName = DESCRIPTIONS.bridge.toolNames.mcp;

export const registerBridgeTool: RegisterTools = ({
  server,
  wallets,
  flags,
}) => {
  server.registerTool(
    toolName,
    {
      title: DESCRIPTIONS.bridge.title,
      description: DESCRIPTIONS.bridge.mcp,
      inputSchema: bridgeSchema,
      annotations: {
        readOnlyHint: false,
        destructiveHint: false,
        idempotentHint: false,
      },
    },
    safeHandler(async input => {
      const result = await bridge({ ...input, ...flags }, wallets);

      if (result.isErr()) {
        return mcpError(result);
      }

      return mcpSuccessJson(result.value);
    })
  );
};
