import { resultFromPromise } from '@agentcash/neverthrow';

import { log } from '@/shared/log';
import {
  discoverResources,
  discoverResourcesSchema,
} from '@/operations/discover';
import { DESCRIPTIONS } from '@/shared/descriptions';

import { mcpError, mcpSuccessJson, safeHandler } from './response';

import type { RegisterTools } from '@/server/types';

const toolName = 'discover_api_endpoints';
const OPENAPI_TRIED_PATHS = '/openapi.json, /.well-known/x402';

export const registerDiscoveryTools: RegisterTools = ({ server, flags }) => {
  server.registerTool(
    toolName,
    {
      title: 'Discover API Endpoints',
      description: DESCRIPTIONS.discoverApiEndpoints.mcp,
      inputSchema: discoverResourcesSchema,
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: true,
      },
    },
    safeHandler(async args => {
      log.info(`Discovering resources for: ${args.url}`);

      const discoverResult = await resultFromPromise(
        'discover',
        toolName,
        discoverResources(toolName, args, { flags }),
        e => ({
          cause: 'discover' as const,
          message: e instanceof Error ? e.message : String(e),
        })
      );

      if (discoverResult.isErr()) {
        return mcpError(discoverResult);
      }

      const result = discoverResult.value;

      if (result.found) {
        return mcpSuccessJson(result);
      }

      if (result.cause === 'not_found') {
        return mcpSuccessJson({
          found: false,
          origin: result.origin,
          error: `No OpenAPI spec found. Tried: ${OPENAPI_TRIED_PATHS}`,
        });
      }

      return mcpSuccessJson({
        found: false,
        cause: result.cause,
        error: result.message ?? `Failed to fetch OpenAPI spec`,
        hint:
          hintMap[result.cause] ??
          `The server returned an unparseable response. Tried: ${OPENAPI_TRIED_PATHS}`,
      });
    })
  );
};

const hintMap = {
  timeout: 'The server may be slow or unreachable. Try again later.',
  network:
    'Could not reach the server. Check the network connection and try again.',
  invalid_input: 'Invalid input. Please check the input and try again.',
};
