import z from 'zod';

import { coreRequestSchema, fetchShape } from './core';

export const mcpBodySchema = z
  .union([
    z
      .string()
      .describe(
        'Raw request body string. Passed through to the underlying fetch call as-is.'
      ),
    z
      .record(z.string(), z.unknown())
      .transform(json => JSON.stringify(json))
      .describe('JSON object to be sent as the request body'),
  ])
  .optional()
  .describe(
    'Request body. Can be a string or an object that will be stringified.'
  );

export const mcpRequestSchema = coreRequestSchema.extend({
  body: mcpBodySchema,
  headers: z
    .record(z.string(), z.string())
    .optional()
    .default({})
    .transform(headers =>
      Object.fromEntries(
        Object.entries(headers).map(([key, value]) => [key, value.trim()])
      )
    )
    .describe('Additional headers to include as a key-value pair'),
});

export const mcpFetchRequestSchema = mcpRequestSchema.extend(fetchShape);
