import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';

import { registerFetchTool } from './tools/fetch';
import { registerWalletTools } from './tools/wallet';
import { registerCheckEndpointTool } from './tools/check-endpoint';
import { registerRedeemInviteTool } from './tools/redeem-invite';
import { registerTelemetryTools } from './tools/telemetry';
import { registerDiscoveryTools } from './tools/discover-resources';
import { registerSettingsTools } from './tools/settings';
import { registerBridgeTool } from './tools/bridge';
import { registerSearchTool } from './tools/search';

import { MCP_VERSION } from './lib/version';

import { log } from '@/shared/log';
import { redeemInviteCode } from '@/shared/redeem-invite';

import { buildServerInstructions } from '@/shared/descriptions';
import { loadUserOrigins } from '@/shared/user-origins';
import { getWallet } from '@/wallet';

import type { Command } from '@/types';

export const startServer: Command = async flags => {
  log.info('Starting agentcash...');

  const { invite, sessionId } = flags;

  const walletResult = await getWallet();

  if (walletResult.isErr()) {
    log.error(JSON.stringify(walletResult.error, null, 2));
    process.exit(1);
  }

  const wallets = walletResult.value;

  const code = invite ?? process.env.INVITE_CODE;

  if (code) {
    await redeemInviteCode('startServer', { code }, flags, wallets);
  }

  const serverInstructions = buildServerInstructions(loadUserOrigins());

  const server = new McpServer(
    {
      name: 'agentcash',
      title: 'AgentCash',
      version: MCP_VERSION,
      websiteUrl: 'https://agentcash.dev',
      icons: [{ src: 'https://agentcash.dev/favicon.svg' }],
      description: serverInstructions,
    },
    {
      instructions: serverInstructions,
    }
  );

  const props = {
    server,
    wallets,
    flags,
    sessionId,
  };

  registerFetchTool(props);
  registerWalletTools(props);
  registerCheckEndpointTool(props);
  registerRedeemInviteTool(props);
  registerDiscoveryTools(props);
  registerTelemetryTools(props);
  registerSettingsTools(props);
  registerBridgeTool(props);
  registerSearchTool(props);

  const transport = new StdioServerTransport();
  await server.connect(transport);

  const shutdown = async () => {
    log.info('Shutting down...');
    await server.close();
    process.exit(0);
  };

  process.on('SIGINT', () => void shutdown());
  process.on('SIGTERM', () => void shutdown());
};
