import { mcpSuccessJson, safeHandler } from './response';

import { log } from '@/shared/log';
import { checkEndpoint } from '@/operations/check-endpoint';
import { DESCRIPTIONS, TOOL_PARAMS } from '@/shared/descriptions';

import { mcpRequestSchema, mcpBodySchema } from '@/shared/request/schemas/mcp';

import type { RegisterTools } from '@/server/types';
import { RequestMethod } from '@/shared/request/types';
import z from 'zod';

const toolName = 'check_endpoint_schema';

export const registerCheckEndpointTool: RegisterTools = ({
  server,
  wallets,
  flags,
}) => {
  server.registerTool(
    toolName,
    {
      title: 'Check Endpoint Schema',
      description: DESCRIPTIONS.checkEndpointSchema.mcp,
      inputSchema: mcpRequestSchema.extend({
        method: z
          .enum(RequestMethod)
          .optional()
          .describe(TOOL_PARAMS.checkEndpointSchema.method),
        body: mcpBodySchema.describe(TOOL_PARAMS.checkEndpointSchema.body),
      }),
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: true,
      },
    },
    safeHandler(async input => {
      log.info('Querying endpoint', {
        url: input.url,
        method: input.method,
        hasSampleInputBody: !!input.body,
      });

      const result = await checkEndpoint(toolName, input, { wallets, flags });

      if (!result.found) {
        log.error('[checkEndpoint] failed', {
          surface: toolName,
          url: input.url,
          cause: result.cause,
          message: result.message,
        });
        return mcpSuccessJson({
          message: 'No endpoint schema found for this URL.',
          url: input.url,
        });
      }

      if (result.advisories.length === 0) {
        return mcpSuccessJson({
          message: 'No endpoint schema found for this URL.',
          url: input.url,
        });
      }

      return mcpSuccessJson({
        url: input.url,
        results: result.advisories,
      });
    })
  );
};
