import z from 'zod';
import { mcpError, mcpSuccessStructuredJson } from './response';

import { redeemInviteCode } from '@/shared/redeem-invite';
import { DESCRIPTIONS, TOOL_PARAMS } from '@/shared/descriptions';

import type { RegisterTools } from '@/server/types';
import { Network } from '@agentcash/networks';

const SURFACE = 'server:redeem-invite';

export const registerRedeemInviteTool: RegisterTools = ({
  server,
  wallets,
  flags,
}) => {
  server.registerTool(
    'redeem_invite',
    {
      title: 'Redeem Invite',
      description: DESCRIPTIONS.redeemInvite.mcp,
      inputSchema: z.object({
        code: z.string().min(1).describe(TOOL_PARAMS.redeemInvite.code),
      }),
      outputSchema: z.object({
        redeemed: z.literal(true),
        amount: z.string().describe(TOOL_PARAMS.redeemInvite.output.amount),
        txHash: z.string().describe(TOOL_PARAMS.redeemInvite.output.txHash),
      }),
      annotations: {
        readOnlyHint: false, // Modifies wallet balance
        destructiveHint: false, // Additive (adds funds), not destructive
        idempotentHint: false, // Same code can't be redeemed twice - second attempt fails
        openWorldHint: true,
      },
    },
    async args => {
      const result = await redeemInviteCode(
        SURFACE,
        { code: args.code },
        flags,
        wallets
      );

      if (result.isErr()) {
        return mcpError(result, { isError: true });
      }

      const { amount, txHash, solanaTxHash, network } = result.value;
      const effectiveTxHash = solanaTxHash ?? txHash;
      const explorerUrl =
        solanaTxHash || network === Network.SOLANA
          ? `https://solscan.io/tx/${effectiveTxHash}`
          : `https://basescan.org/tx/${effectiveTxHash}`;

      return mcpSuccessStructuredJson({
        redeemed: true,
        amount: `${amount} USDC`,
        txHash: effectiveTxHash,
        explorerUrl,
      });
    }
  );
};
