import { resultFromPromise } from '@agentcash/neverthrow';

import { log } from '@/shared/log';
import { search, searchSchema } from '@/operations/search';
import { DESCRIPTIONS } from '@/shared/descriptions';

import {
  mcpError,
  mcpErrorJson,
  mcpSuccessJson,
  safeHandler,
} from './response';

import type { RegisterTools } from '@/server/types';

const TOOL_NAME = 'search';

export const registerSearchTool: RegisterTools = ({
  server,
  wallets,
  flags,
}) => {
  server.registerTool(
    TOOL_NAME,
    {
      title: 'Search APIs',
      description: DESCRIPTIONS.search.mcp,
      inputSchema: searchSchema,
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: true,
      },
    },
    safeHandler(async args => {
      log.info(`[search] query: ${args.query}`);

      const searchResult = await resultFromPromise(
        'search',
        TOOL_NAME,
        search(args, { surface: TOOL_NAME, wallets, flags }),
        e => ({
          cause: 'search' as const,
          message: e instanceof Error ? e.message : String(e),
        })
      );

      if (searchResult.isErr()) {
        return mcpError(searchResult);
      }

      const result = searchResult.value;

      if (!result.success) {
        return mcpErrorJson({
          error: result.message,
          cause: result.cause,
          details: result.details,
        });
      }

      return mcpSuccessJson({
        success: result.success,
        results: result.results,
      });
    })
  );
};
