import { z } from 'zod';

import { getSettings, setSettings } from '@/shared/settings';
import { DEFAULT_MAX_AMOUNT } from '@/operations/fetch/types';

import { mcpSuccessStructuredJson, safeHandler } from './response';
import { DESCRIPTIONS } from '@/shared/descriptions';

import type { RegisterTools } from '@/server/types';

export const registerSettingsTools: RegisterTools = ({ server }) => {
  server.registerTool(
    'update_settings',
    {
      title: 'Update Settings',
      description: DESCRIPTIONS.updateSettings.mcp,
      inputSchema: z.object({
        maxAmount: z
          .number()
          .positive()
          .optional()
          .describe(
            `Maximum amount (USD) to pay per fetch request. Current default: $${DEFAULT_MAX_AMOUNT}.`
          ),
      }),
      annotations: {
        readOnlyHint: false,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: false,
      },
    },
    safeHandler(input => {
      if (input.maxAmount !== undefined) {
        setSettings({ maxAmount: input.maxAmount });
      }

      const settings = getSettings();

      return Promise.resolve(mcpSuccessStructuredJson(settings));
    })
  );

  server.registerTool(
    'get_settings',
    {
      title: 'Get Settings',
      description: DESCRIPTIONS.getSettings.mcp,
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: false,
      },
    },
    safeHandler(() => {
      const settings = getSettings();

      return Promise.resolve(mcpSuccessStructuredJson(settings));
    })
  );
};
