import { getBalances, listAccountsWithBalances } from '@/operations/wallet';

import { mcpSuccessStructuredJson } from './response';
import { DESCRIPTIONS } from '@/shared/descriptions';

import type { RegisterTools } from '@/server/types';

export const registerWalletTools: RegisterTools = ({
  server,
  wallets,
  flags,
}) => {
  const getBalanceToolName = 'get_balance';
  server.registerTool(
    getBalanceToolName,
    {
      title: 'Get Balance',
      description: DESCRIPTIONS.getBalance.mcp,
    },
    async () => {
      const result = await getBalances(getBalanceToolName, wallets, flags);
      return mcpSuccessStructuredJson({
        balance: result.totalBalance,
      });
    }
  );

  const listAccountsToolName = 'list_accounts';

  server.registerTool(
    listAccountsToolName,
    {
      title: 'Get Accounts',
      description: DESCRIPTIONS.listAccounts.mcp,
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: true,
      },
    },
    async () => {
      const result = await listAccountsWithBalances(
        listAccountsToolName,
        wallets,
        flags
      );
      return mcpSuccessStructuredJson(result);
    }
  );
};
