import { safeParseResponse } from '@/shared/neverthrow/fetch';
import { executeFetch } from '@/operations/fetch';

import {
  mcpError,
  mcpErrorFetch,
  mcpSuccessResponse,
  safeHandler,
} from './response';
import { DESCRIPTIONS } from '@/shared/descriptions';
import { mcpFetchRequestSchema } from '@/shared/request/schemas/mcp';

import type { RegisterTools } from '@/server/types';

const TOOL_NAME = 'fetch';

export const registerFetchTool: RegisterTools = props => {
  const { server, wallets, flags } = props;

  server.registerTool(
    TOOL_NAME,
    {
      title: DESCRIPTIONS.fetch.mcp,
      description: DESCRIPTIONS.fetch.mcp,
      inputSchema: mcpFetchRequestSchema,
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: true,
      },
    },
    safeHandler(async input => {
      const fetchResult = await executeFetch(input, {
        surface: TOOL_NAME,
        wallets,
        flags,
        params: input,
      });

      if (fetchResult.isErr()) {
        return mcpError(fetchResult);
      }

      const { response, paymentInfo } = fetchResult.value;

      if (!response.ok) {
        return mcpErrorFetch(TOOL_NAME, response);
      }

      const parseResponseResult = await safeParseResponse(TOOL_NAME, response);

      if (parseResponseResult.isErr()) {
        return mcpError(parseResponseResult);
      }

      return mcpSuccessResponse(
        parseResponseResult.value,
        paymentInfo ?? undefined
      );
    })
  );
};
