import z from 'zod';

import { log } from '@/shared/log';
import { submitErrorReport } from '@/operations/report-error';
import { mcpError, mcpSuccessStructuredJson } from './response';
import { DESCRIPTIONS, TOOL_PARAMS } from '@/shared/descriptions';

import type { RegisterTools } from '@/server/types';

const toolName = 'report_error';

export const registerTelemetryTools: RegisterTools = ({
  server,
  wallets,
  flags,
}) => {
  server.registerTool(
    toolName,
    {
      title: 'Report Error',
      description: DESCRIPTIONS.reportError.mcp,
      inputSchema: z.object({
        tool: z.string().describe(TOOL_PARAMS.reportError.tool),
        resource: z
          .string()
          .optional()
          .describe(TOOL_PARAMS.reportError.resource),
        summary: z.string().describe(TOOL_PARAMS.reportError.summary),
        errorMessage: z.string().describe(TOOL_PARAMS.reportError.errorMessage),
        stack: z.string().optional().describe(TOOL_PARAMS.reportError.stack),
        fullReport: z
          .string()
          .optional()
          .describe(TOOL_PARAMS.reportError.fullReport),
      }),
      outputSchema: z.object({
        submitted: z.literal(true),
        reportId: z.string().describe(TOOL_PARAMS.reportError.output.reportId),
        message: z.string().describe(TOOL_PARAMS.reportError.output.message),
      }),
      annotations: {
        readOnlyHint: false,
        destructiveHint: false,
        idempotentHint: false,
        openWorldHint: true,
      },
    },
    async input => {
      log.info('Submitting error report', {
        tool: input.tool,
        resource: input.resource,
        summary: input.summary,
      });

      const result = await submitErrorReport(
        toolName,
        {
          tool: input.tool,
          summary: input.summary,
          errorMessage: input.errorMessage,
          resource: input.resource,
          stack: input.stack,
          fullReport: input.fullReport,
        },
        wallets.evm.address,
        flags.dev
      );

      if (result.isErr()) {
        log.error('Failed to submit error report', result.error);
        return mcpError(result, { isError: true });
      }

      log.info('Error report submitted successfully', {
        reportId: result.value.reportId,
      });

      return mcpSuccessStructuredJson(result.value);
    }
  );
};
