import { safeStringifyJson } from '@/shared/neverthrow/json';

import { parsedResponseToToolContentPart } from './lib';
import {
  fetchHttpErr,
  isFetchError,
  safeParseResponse,
} from '@/shared/neverthrow/fetch';

import type { JsonStringifyValue } from '@/shared/neverthrow/json/types';
import type { CallToolResult } from '@modelcontextprotocol/sdk/types.js';
import type { BaseError, Err } from '@agentcash/neverthrow/types';
import type { BaseX402Error } from '@/shared/protocols/x402/types';
import type { BaseMppError } from '@/shared/protocols/mpp/types';
import type { BaseFetchError } from '@/shared/neverthrow/fetch/types';

const buildMcpError = (
  content: CallToolResult['content'],
  options?: { isError?: boolean }
): CallToolResult => {
  return {
    content,
    // Default: omit isError so siblings survive parallel calls.
    // Tools with outputSchema MUST pass isError: true so the SDK
    // skips output validation on error paths.
    ...(options?.isError ? { isError: true as const } : {}),
  };
};

export const mcpErrorJson = (
  error: JsonStringifyValue,
  options?: { isError?: boolean }
): CallToolResult => {
  return safeStringifyJson('mcp-error-json', error).match(
    success =>
      buildMcpError([{ type: 'text' as const, text: success }], options),
    error =>
      buildMcpError(
        [{ type: 'text' as const, text: JSON.stringify(error, null, 2) }],
        options
      )
  );
};

export const mcpError = async (
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  err: Err<any, BaseX402Error | BaseMppError | BaseFetchError | BaseError>,
  options?: { isError?: boolean }
) => {
  const { error } = err;
  if (isFetchError(error)) {
    switch (error.cause) {
      case 'network':
      case 'parse':
        return mcpErrorJson({ ...error }, options);
      case 'http':
        const { response, ...rest } = error;
        const parseResponseResult = await safeParseResponse(
          'mcp-error-fetch-parse-response',
          response
        );
        const httpContent: CallToolResult['content'] = [
          { type: 'text' as const, text: JSON.stringify(rest, null, 2) },
          ...parseResponseResult.match(
            success => [parsedResponseToToolContentPart(success)],
            () => []
          ),
        ];
        return buildMcpError(httpContent, options);
    }
  }
  return mcpErrorJson({ ...error }, options);
};

export const mcpErrorFetch = async (surface: string, response: Response) => {
  return mcpError(fetchHttpErr(surface, response));
};
